import { createSlice, createAsyncThunk } from "@reduxjs/toolkit";
import axios from "../../axios";

export const fetchRasps = createAsyncThunk("schedules/fetchRasps", async () => {
  const { data } = await axios.get("/schedules");
  return data;
});

export const fetchRemoveRasp = createAsyncThunk(
    "delete-schedule/fetchRemoveRasp",
    async (id) => axios.delete(`/delete-schedule/${id}`)
  );
  
  
const initialState = {
    schedules: {
    items: [],
    status: "loading",
  },
};

const raspsSlice = createSlice({
  name: "schedules",
  initialState,
  reducers: {},
  extraReducers: {
    [fetchRasps.pending]: (state) => {
      state.schedules.status = "loadingfetch";
    },
    [fetchRasps.fulfilled]: (state, action) => {
      state.schedules.items = action.payload;
      state.schedules.status = "loadedfetch";
    },
    [fetchRasps.rejected]: (state) => {
      state.schedules.items = [];
      state.schedules.status = "error";
    },
    [fetchRemoveRasp.pending]: (state, action) => {
      state.schedules.items = state.schedules.items.filter(
        (obj) => obj.id !== action.meta.arg
      );
    },
  },
});



export const raspsReducer = raspsSlice.reducer;
